import { useState } from 'react';
import { ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid, PieChart, Pie, Cell } from 'recharts';
import { Card, CardContent, CardHeader, CardTitle } from '../../../components/ui/Card';
import { ChartSkeleton } from '../../../components/ui/ChartSkeleton';
import { AnimatedCounter } from '../../../components/ui/AnimatedCounter';

const dailyData = [
  { date: 'Mon', jobs: 12, manual: 4 },
  { date: 'Tue', jobs: 18, manual: 6 },
  { date: 'Wed', jobs: 15, manual: 3 },
  { date: 'Thu', jobs: 24, manual: 8 },
  { date: 'Fri', jobs: 28, manual: 12 },
  { date: 'Sat', jobs: 8, manual: 2 },
  { date: 'Sun', jobs: 5, manual: 0 },
];

const statusData = [
  { name: 'Applied', value: 450 },
  { name: 'Review', value: 120 },
  { name: 'Interview', value: 45 },
  { name: 'Rejected', value: 180 },
];

const COLORS = ['#3b82f6', '#8b5cf6', '#10b981', '#ef4444'];

// Custom Tooltip Component
const CustomTooltip = ({ active, payload, label }: { active?: boolean; payload?: Record<string, any>[]; label?: string }) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-white dark:bg-gray-900 p-3 rounded-lg shadow-lg border border-gray-200 dark:border-gray-700 animate-in fade-in duration-200">
        <p className="font-semibold text-gray-900 dark:text-gray-100 mb-2">{label}</p>
        {payload.map((entry: Record<string, any>, index: number) => (
          <div key={index} className="flex items-center gap-2 text-sm">
            {/* eslint-disable-next-line */}
            <div className="w-3 h-3 rounded-full" style={{ backgroundColor: entry.color }} />
            <span className="text-gray-600 dark:text-gray-400">{entry.name}:</span>
            <span className="font-semibold text-gray-900 dark:text-gray-100">{entry.value}</span>
          </div>
        ))}
      </div>
    );
  }
  return null;
};

// Custom Pie Tooltip
const CustomPieTooltip = ({ active, payload }: { active?: boolean; payload?: Record<string, any>[] }) => {
  if (active && payload && payload.length) {
    const data = payload[0];
    if (!data) return null;
    const total = statusData.reduce((sum, item) => sum + item.value, 0);
    const percentage = ((data.value / total) * 100).toFixed(1);

    return (
      <div className="bg-white dark:bg-gray-900 p-3 rounded-lg shadow-lg border border-gray-200 dark:border-gray-700 animate-in fade-in duration-200">
        <p className="font-semibold text-gray-900 dark:text-gray-100 mb-1">{data.name}</p>
        <p className="text-sm text-gray-600 dark:text-gray-400">
          <span className="font-semibold text-gray-900 dark:text-gray-100">{data.value}</span> applications
        </p>
        <p className="text-xs text-gray-500 dark:text-gray-500 mt-1">{percentage}% of total</p>
      </div>
    );
  }
  return null;
};

export function ChartsSection({ loading }: { loading?: boolean }) {
  const [activeIndex, setActiveIndex] = useState<number | null>(null);
  const [hiddenSegments, setHiddenSegments] = useState<Set<number>>(new Set());

  const handleLegendClick = (index: number) => {
    setHiddenSegments(prev => {
      const newSet = new Set(prev);
      if (newSet.has(index)) {
        newSet.delete(index);
      } else {
        newSet.add(index);
      }
      return newSet;
    });
  };

  const visibleData = statusData.filter((_, index) => !hiddenSegments.has(index));
  const totalActive = visibleData.reduce((sum, item) => sum + item.value, 0);

  if (loading) {
    return (
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-7">
        <div className="col-span-4">
          <ChartSkeleton />
        </div>
        <div className="col-span-3">
          <ChartSkeleton />
        </div>
      </div>
    );
  }

  return (
    <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-7">
      {/* Main Bar Chart */}
      <Card className="col-span-4">
        <CardHeader>
          <CardTitle>Application Volume</CardTitle>
        </CardHeader>
        <CardContent className="pl-0">
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={dailyData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#374151" opacity={0.2} />
                <XAxis
                  dataKey="date"
                  stroke="#888888"
                  fontSize={12}
                  tickLine={false}
                  axisLine={false}
                />
                <YAxis
                  stroke="#888888"
                  fontSize={12}
                  tickLine={false}
                  axisLine={false}
                  tickFormatter={(value) => `${value}`}
                />
                <Tooltip content={<CustomTooltip />} cursor={{ fill: 'rgba(59, 130, 246, 0.1)' }} />
                <Bar
                  dataKey="jobs"
                  fill="#3b82f6"
                  radius={[4, 4, 0, 0]}
                  name="Auto Apply"
                  isAnimationActive={true}
                  animationDuration={1000}
                  animationEasing="ease-out"
                />
                <Bar
                  dataKey="manual"
                  fill="#8b5cf6"
                  radius={[4, 4, 0, 0]}
                  name="Manual"
                  isAnimationActive={true}
                  animationDuration={1000}
                  animationEasing="ease-out"
                  animationBegin={200}
                />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </CardContent>
      </Card>

      {/* Pie Chart Status */}
      <Card className="col-span-3">
        <CardHeader>
          <CardTitle>Pipeline Status</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="h-[300px] w-full relative">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={visibleData}
                  cx="50%"
                  cy="50%"
                  innerRadius={80}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                  isAnimationActive={true}
                  animationBegin={0}
                  animationDuration={800}
                  animationEasing="ease-out"
                  onMouseEnter={(_, index) => setActiveIndex(index)}
                  onMouseLeave={() => setActiveIndex(null)}
                >
                  {visibleData.map((entry, index) => {
                    const originalIndex = statusData.indexOf(entry);
                    const isActive = activeIndex === index;
                    return (
                      <Cell
                        key={`cell-${index}`}
                        fill={COLORS[originalIndex % COLORS.length]}
                        opacity={isActive ? 1 : 0.8}
                        // eslint-disable-next-line
                        style={{
                          filter: isActive ? 'brightness(1.1)' : 'brightness(1)',
                          transition: 'all 0.3s ease',
                          cursor: 'pointer'
                        }}
                      />
                    );
                  })}
                </Pie>
                <Tooltip content={<CustomPieTooltip />} />
              </PieChart>
            </ResponsiveContainer>
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
              <div className="text-center">
                <div className="text-3xl font-bold">
                  <AnimatedCounter value={totalActive} />
                </div>
                <div className="text-xs text-gray-500">Total Active</div>
              </div>
            </div>
          </div>
          <div className="mt-4 flex flex-wrap justify-center gap-4 text-sm">
            {statusData.map((entry, index) => {
              const isHidden = hiddenSegments.has(index);
              return (
                <button
                  key={entry.name}
                  onClick={() => handleLegendClick(index)}
                  className={`flex items-center gap-2 transition-all duration-200 hover:scale-105 cursor-pointer ${isHidden ? 'opacity-40' : 'opacity-100'
                    }`}
                >
                  <div
                    className="h-3 w-3 rounded-full transition-transform duration-200"
                    // eslint-disable-next-line
                    style={{
                      backgroundColor: COLORS[index % COLORS.length],
                      transform: isHidden ? 'scale(0.8)' : 'scale(1)'
                    }}
                  />
                  <span className={`text-gray-600 dark:text-gray-400 ${isHidden ? 'line-through' : ''}`}>
                    {entry.name}
                  </span>
                </button>
              );
            })}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect, useCallback, useRef } from 'react';
import { Terminal as TerminalIcon, Play } from 'lucide-react';
import { EmptyState } from '../../components/ui/EmptyState';
import { LogTerminal } from './components/LogTerminal';
import type { LogEntry } from './components/LogTerminal';
import { LogControls } from './components/LogControls';
import { useWebSocket } from '../../hooks/use-socket';
import { useAuth } from '../../contexts/AuthContext';
import { Button } from '../../components/ui/Button';
import { toast } from '../../components/ui/Toast';
import apiClient from '../../lib/api';

// Get WebSocket URL from environment or default
const WS_BASE_URL = import.meta.env.VITE_WS_URL || 'ws://localhost:8000/ws';

export function Logs() {
  const { user } = useAuth();
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [paused, setPaused] = useState(false);
  const [botRunning, setBotRunning] = useState(false);
  const logIdCounter = useRef(0);

  // Connect to WebSocket for real-time logs
  const token = localStorage.getItem('access_token');
  const wsUrl = user && token ? `${WS_BASE_URL}?token=${token}` : '';
  const { isConnected, messages } = useWebSocket(wsUrl);

  // Process only the latest WebSocket message to avoid re-processing older entries
  useEffect(() => {
    if (paused || !isConnected || messages.length === 0) return;

    const msg = messages[0];

    // Handle log events from backend
    if (msg.event === 'log') {
      const newLog: LogEntry = {
        id: msg.id || `log-${++logIdCounter.current}`,
        timestamp: msg.timestamp || new Date().toLocaleTimeString(),
        level: msg.level || 'info',
        message: msg.message || msg.text || 'Unknown log message'
      };
      setLogs(prev => [...prev.slice(-99), newLog]); // Keep last 100
    }

    // Handle bot status events
    if (msg.event === 'bot_status') {
      if (msg.status === 'completed' || msg.status === 'error') {
        setBotRunning(false);
      }
    }
  }, [messages, paused, isConnected]);

  const handleClear = () => setLogs([]);

  const handleStartBot = useCallback(async () => {
    try {
      setBotRunning(true);
      const response = await apiClient.post('/bot/start');
      toast.success(response.data.message || 'Bot started!');

      // Add a local log entry
      setLogs(prev => [...prev, {
        id: `log-${++logIdCounter.current}`,
        timestamp: new Date().toLocaleTimeString(),
        level: 'info',
        message: '🚀 Bot start requested — waiting for logs...'
      }]);
    } catch (error: any) {
      setBotRunning(false);
      const message = error?.response?.data?.detail || 'Failed to start bot';
      toast.error(message);
    }
  }, []);

  return (
    <div className="space-y-6 h-[calc(100vh-140px)] flex flex-col animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight text-gray-900 dark:text-white">System Logs</h1>
          <p className="text-gray-500 dark:text-gray-400 mt-1">
            Real-time bot execution output {isConnected ? '(Connected)' : '(Disconnected)'}
          </p>
        </div>
        <Button
          variant="primary"
          onClick={handleStartBot}
          isLoading={botRunning}
          disabled={botRunning}
        >
          <Play className="h-4 w-4 mr-2" />
          {botRunning ? 'Bot Running...' : 'Start Bot'}
        </Button>
      </div>

      <div className="flex-1 flex flex-col">
        <LogControls
          paused={paused}
          setPaused={setPaused}
          clearLogs={handleClear}
          connected={isConnected}
        />

        {logs.length === 0 ? (
          <div className="flex-1 flex items-center justify-center border border-dashed border-gray-200 dark:border-gray-800 rounded-lg m-4">
            <EmptyState
              icon={TerminalIcon}
              title="No system logs"
              description="Click 'Start Bot' to begin the automation process."
              action={{ label: "Start Bot", onClick: handleStartBot }}
            />
          </div>
        ) : (
          <LogTerminal logs={logs} paused={paused} />
        )}
      </div>
    </div>
  );
}

export default Logs;

import { useState, useCallback } from 'react';
import { Upload } from 'lucide-react';
import { cn } from '../../../lib/utils';
import { Button } from '../../../components/ui/Button';

interface UploadAreaProps {
  onUpload?: (file: File) => Promise<void>;
  disabled?: boolean;
}

export function UploadArea({ onUpload, disabled = false }: UploadAreaProps) {
  const [dragging, setDragging] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [progress, setProgress] = useState(0);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setDragging(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setDragging(false);
    const files = e.dataTransfer.files;
    if (files.length > 0 && files[0]) {
      handleUpload(files[0]);
    }
  }, [onUpload]);

  const handleUpload = async (file: File) => {
    if (!onUpload) return;

    setUploading(true);
    setProgress(0);

    try {
      // Simulate progress while upload happens
      const progressInterval = setInterval(() => {
        setProgress(prev => Math.min(prev + 10, 90));
      }, 200);

      // Call the actual upload function passed from parent
      await onUpload(file);

      clearInterval(progressInterval);
      setProgress(100);

      setTimeout(() => {
        setUploading(false);
        setProgress(0);
      }, 500);
    } catch (error) {
      setUploading(false);
      setProgress(0);
      throw error;
    }
  };

  return (
    <div
      className={cn(
        "relative rounded-xl border-2 border-dashed transition-all duration-200 p-8 flex flex-col items-center justify-center text-center min-h-[200px]",
        dragging ? "border-blue-500 bg-blue-50 dark:bg-blue-900/20" : "border-gray-200 dark:border-gray-800 hover:border-gray-300 dark:hover:border-gray-700",
        uploading && "pointer-events-none opacity-80"
      )}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      {uploading ? (
        <div className="w-full max-w-xs space-y-4">
          <div className="flex items-center justify-center h-12 w-12 rounded-full bg-blue-100 dark:bg-blue-900 text-blue-600 dark:text-blue-400 mx-auto animate-pulse">
            <Upload className="h-6 w-6" />
          </div>
          <div>
            <p className="font-medium text-gray-900 dark:text-gray-100">Uploading Resume...</p>
            <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">Please wait while we process your file.</p>
          </div>
          <div className="h-2 w-full bg-gray-100 dark:bg-gray-800 rounded-full overflow-hidden">
            {/* eslint-disable-next-line */}
            <div className="h-full bg-blue-500 transition-all duration-300 ease-out" style={{ width: `${progress}%` }} />
          </div>
        </div>
      ) : (
        <div className="space-y-4">
          <div className="flex items-center justify-center h-12 w-12 rounded-full bg-gray-100 dark:bg-gray-800 mx-auto">
            <Upload className="h-6 w-6 text-gray-400" />
          </div>
          <div>
            <p className="font-medium text-gray-900 dark:text-gray-100">Click to upload or drag and drop</p>
            <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">PDF, DOCX up to 10MB</p>
          </div>
          <Button variant="outline" size="sm" onClick={() => document.getElementById('file-upload')?.click()} disabled={disabled}>
            Select File
          </Button>
          <input
            id="file-upload"
            type="file"
            className="hidden"
            accept=".pdf,.docx"
            aria-label="Upload resume file"
            onChange={(e) => {
              const file = e.target.files?.[0];
              if (file) handleUpload(file);
            }}
          />
        </div>
      )}
    </div>
  );
}
